parameters.jsCode:
const client = $('Split In Batches').item.json;
const allContent = $input.all().map(i => i.json);

// Calcular rango del mes anterior
const now = new Date();
const firstDayLastMonth = new Date(now.getFullYear(), now.getMonth() - 1, 1);
const firstDayCurrentMonth = new Date(now.getFullYear(), now.getMonth(), 1);

// Filtrar contenido del mes anterior
const lastMonthContent = allContent.filter(c => {
  if (!c.published_at) return false;
  const pubDate = new Date(c.published_at);
  return pubDate >= firstDayLastMonth && pubDate < firstDayCurrentMonth;
});

// Calcular metricas
const metrics = {
  videos: lastMonthContent.filter(c => c.type === 'video').length,
  photos: lastMonthContent.filter(c => c.type === 'photo').length,
  carousels: lastMonthContent.filter(c => c.type === 'carousel').length,
  published: lastMonthContent.filter(c => c.status === 'published').length,
  total: lastMonthContent.length
};

const monthName = firstDayLastMonth.toLocaleDateString('es-CO', { month: 'long', year: 'numeric' });

// Construir HTML del reporte
const html = `
<!DOCTYPE html>
<html lang="es">
<head><meta charset="UTF-8"><style>
body { font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto; color: #333; }
h1 { color: #1a1a2e; border-bottom: 2px solid #e94560; padding-bottom: 10px; }
table { width: 100%; border-collapse: collapse; margin: 20px 0; }
th { background: #1a1a2e; color: white; padding: 10px; text-align: left; }
td { padding: 10px; border-bottom: 1px solid #eee; }
.total { font-weight: bold; background: #f5f5f5; }
.footer { margin-top: 30px; font-size: 12px; color: #666; }
</style></head>
<body>
<h1>Reporte ${monthName}</h1>
<h2>${client.company}</h2>
<p>Aqui tienes el resumen de actividad de contenido UGC del mes pasado:</p>
<table>
<tr><th>Tipo de Contenido</th><th>Cantidad</th></tr>
<tr><td>Videos</td><td>${metrics.videos}</td></tr>
<tr><td>Fotos</td><td>${metrics.photos}</td></tr>
<tr><td>Carruseles</td><td>${metrics.carousels}</td></tr>
<tr class="total"><td>Total publicados</td><td>${metrics.published}</td></tr>
<tr class="total"><td>Total entregados</td><td>${metrics.total}</td></tr>
</table>
<p>Para ver el detalle completo o descargar los archivos, ingresa a tu portal de cliente.</p>
<div class="footer"><p>Equipo UGC Colombia | hola@agenciaugccolombia.co</p></div>
</body></html>`;

return [{ json: { html, client, metrics, monthName } }];

